import React from 'react';

interface TicketVentaProps {
  cuenta: any;
  areaNombre?: string;
  cajeroNombre?: string;
}

export const TicketVenta: React.FC<TicketVentaProps> = ({ cuenta, areaNombre }) => {
  if (!cuenta) return null;

  const totalOriginal = cuenta.detalleCuentas?.reduce((acc: number, det: any) =>
    acc + (Number(det.cantidad) * Number(det.precio_unitario)), 0) || 0;
  
  const descuento = Number(cuenta.descuento || 0);
  const propina = Number(cuenta.propina || 0);
  const adeudos = Number(cuenta.adeudosPagados || 0);
  const granTotal = totalOriginal - descuento + propina + adeudos;

  // Imagen del golfista convertida a base64
  const golferImgSrc = "data:image/png;base64,";

  return (
    <div id="printable-ticket" className="bg-white text-black hidden print:block absolute top-0 left-0 relative">
      <style>{`
        @media print {
          @page {
            size: 80mm auto !important;
            margin: 2mm !important;
          }
          header, nav, footer, button, input, select {
            display: none !important;
          }
          .grid > div:not(.print-wrapper),
          .lg\\:grid-cols-3 > div:not(.print-wrapper),
          main > div > div:not(.grid) {
            display: none !important;
          }
          html, body, #root, #root > div, main {
            margin: 0 !important;
            padding: 0 !important;
            height: auto !important;
            min-height: 0 !important;
            max-height: none !important;
            overflow: visible !important;
            background: white !important;
          }
          #printable-ticket {
            display: block !important;
            position: absolute;
            left: 2mm !important;
            top: 2mm !important;
            width: 76mm !important;
            max-width: 76mm !important;
            height: auto !important;
            background: white !important;
            color: #000000 !important;
            padding: 8px !important;
            box-sizing: border-box !important;
            font-family: 'Outfit', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif !important;
            -webkit-print-color-adjust: exact !important;
            print-color-adjust: exact !important;
          }
        }

        .ticket-divider {
          border-top: 1px solid #000000 !important;
          margin: 10px 0;
        }

        .ticket-title {
          font-family: 'Outfit', sans-serif;
          font-weight: 800;
          letter-spacing: 1px;
          text-transform: uppercase;
        }
      `}</style>

      {/* CABECERA (Logo a la izquierda e Imagen a la derecha) */}
      <div className="flex justify-between items-center mb-2.5 pt-1">
        {/* LOGO (Alineado a la izquierda) */}
        <div className="text-left">
          <svg
            viewBox="0 0 280 100"
            width="100"
            height="36"
            className="text-left"
          >
            {/* Mountain Silhouette Line */}
            <path
              d="M 10 50 Q 40 38 70 48 T 130 45 T 190 35 T 270 52"
              fill="none"
              stroke="#000000"
              strokeWidth="3.5"
              strokeLinecap="round"
            />
            <path
              d="M 25 51 Q 65 38 105 45 T 185 36 T 255 51"
              fill="none"
              stroke="#000000"
              strokeWidth="2.5"
              strokeLinecap="round"
            />

            {/* CLUB CAMPESTRE Text */}
            <text
              x="140"
              y="28"
              textAnchor="middle"
              fontSize="21"
              fontWeight="900"
              fontFamily="Outfit, sans-serif"
              letterSpacing="4"
              fill="#000000"
            >
              CLUB CAMPESTRE
            </text>

            {/* LOURDES Text with golf ball O */}
            <g transform="translate(15, 60)">
              <text x="5" y="30" fontSize="34" fontWeight="900" fontFamily="Outfit, sans-serif" fill="#000000">L</text>
              <g transform="translate(48, 14)">
                <circle cx="8" cy="11" r="9" fill="#ffffff" stroke="#000000" strokeWidth="2" />
                <circle cx="5" cy="8" r="1" fill="#000000" />
                <circle cx="8" cy="7" r="1" fill="#000000" />
                <circle cx="11" cy="8" r="1" fill="#000000" />
                <circle cx="5" cy="11" r="1" fill="#000000" />
                <circle cx="8" cy="11" r="1" fill="#000000" />
                <circle cx="11" cy="11" r="1" fill="#000000" />
                <circle cx="6" cy="14" r="1" fill="#000000" />
                <circle cx="8" cy="15" r="1" fill="#000000" />
                <circle cx="10" cy="14" r="1" fill="#000000" />
              </g>
              <text x="80" y="30" fontSize="34" fontWeight="900" fontFamily="Outfit, sans-serif" fill="#000000" letterSpacing="2">URDES</text>
            </g>
          </svg>
          <div className="text-[8.5px] font-extrabold tracking-[0.2em] text-black uppercase mt-1">
            Ticket de Consumo
          </div>
        </div>

        {/* IMAGEN DE GOLF SWING (Alineada a la derecha) */}
        <div className="flex-shrink-0 ml-2">
          <img
            src={golferImgSrc}
            alt="Golf Swing"
            className="w-[44px] h-[44px] object-contain"
          />
        </div>
      </div>

      <div className="ticket-divider"></div>

      {/* 2. DATOS GENERALES */}
      <div className="text-[10px] space-y-1 text-black">
        <div className="flex justify-between">
          <span><strong>LUGAR:</strong> {areaNombre || 'GENERAL'}</span>
          {cuenta.socioNombre && <span><strong>SOCIO:</strong> <span className="uppercase font-bold">{cuenta.socioNombre}</span></span>}
        </div>
        <div className="flex justify-between">
          <span><strong>FECHA:</strong> {new Date().toLocaleDateString('es-MX')}</span>
          <span><strong>HORA:</strong> {new Date().toLocaleTimeString('es-MX', { hour: '2-digit', minute: '2-digit', hour12: true })}</span>
        </div>
        {cuenta.metodo_pago && (
          <div className="mt-1">
            <strong>PAGO:</strong> <span className="uppercase text-[9px] border border-black text-black px-1.5 py-0.5 rounded font-bold">{cuenta.metodo_pago}</span>
          </div>
        )}
      </div>

      <div className="ticket-divider"></div>

      {/* 3. CABECERA DE ARTÍCULOS */}
      <div className="flex justify-between text-[9.5px] font-black text-black uppercase tracking-wider mb-2">
        <span>Descripción</span>
        <span>Importe</span>
      </div>

      {/* 4. DETALLE DE CONSUMOS */}
      <div className="space-y-2">
        {cuenta.detalleCuentas?.map((item: any) => (
          <div key={item.id} className="text-[11px] leading-tight text-black">
            <div className="flex justify-between items-start">
              <span className="font-semibold">
                <span className="font-extrabold mr-2">{Number(item.cantidad)}</span>
                {item.producto?.nombre}
                {Number(item.cantidad) > 1 && (
                  <span className="text-[9.5px] font-medium text-slate-800 block pl-4">
                    {Number(item.cantidad)} x ${Number(item.precio_unitario).toFixed(2)} c/u
                  </span>
                )}
              </span>
              <span className="font-bold text-right min-w-[60px] self-end">
                ${(Number(item.cantidad) * Number(item.precio_unitario)).toFixed(2)}
              </span>
            </div>
            {item.notes || item.notas ? (
              <div className="pl-5 text-[9.5px] font-medium italic mt-0.5 text-black">
                {item.notas}
              </div>
            ) : null}
          </div>
        ))}

        {cuenta.adeudosDetalle?.map((adeudo: any, idx: number) => {
          const dateObj = new Date(adeudo.fecha);
          const dateStr = dateObj.toLocaleDateString('es-MX', { day: '2-digit', month: '2-digit' });
          return (
            <div key={`adeudo-header-${idx}`} className="pt-2 border-t border-dashed border-slate-350">
              <span className="text-[9.5px] font-extrabold uppercase text-slate-900 block tracking-wider mb-1">
                📌 Consumos del Adeudo ({adeudo.area || 'General'} - {dateStr})
              </span>
              {adeudo.productos?.map((p: any, pIdx: number) => (
                <div key={`adeudo-prod-${idx}-${pIdx}`} className="text-[11px] leading-tight text-black pl-2 mt-1 flex justify-between">
                  <span>
                    <span className="font-extrabold mr-2">{p.cantidad}</span>
                    {p.nombre} (Adeudo)
                  </span>
                  <span className="font-bold">${Number(p.subtotal).toFixed(2)}</span>
                </div>
              ))}
            </div>
          );
        })}
      </div>

      <div className="ticket-divider"></div>

      {/* 5. TOTALES */}
      <div className="space-y-1.5 text-[11px] text-black">
        <div className="flex justify-between">
          <span>Subtotal</span>
          <span className="font-bold">${totalOriginal.toFixed(2)}</span>
        </div>
        {descuento > 0 && (
          <div className="flex justify-between font-bold">
            <span>Descuento</span>
            <span>-${descuento.toFixed(2)}</span>
          </div>
        )}
        {propina > 0 && (
          <div className="flex justify-between font-bold">
            <span>Propina Sugerida</span>
            <span>+${propina.toFixed(2)}</span>
          </div>
        )}
        {cuenta.adeudosDetalle && cuenta.adeudosDetalle.length > 0 ? (
          cuenta.adeudosDetalle.map((adeudoItem: any, idx: number) => {
            const dateObj = new Date(adeudoItem.fecha);
            const dateStr = dateObj.toLocaleDateString('es-MX', { day: '2-digit', month: '2-digit' });
            return (
              <div key={idx} className="flex justify-between font-bold">
                <span>Adeudo ({adeudoItem.area || 'General'} - {dateStr})</span>
                <span>+${Number(adeudoItem.monto).toFixed(2)}</span>
              </div>
            );
          })
        ) : (
          adeudos > 0 && (
            <div className="flex justify-between font-bold">
              <span>Adeudos Liquidados</span>
              <span>+${adeudos.toFixed(2)}</span>
            </div>
          )
        )}
        
        <div className="ticket-divider"></div>

        <div className="flex justify-between items-center py-1">
          <span className="ticket-title text-[11.5px] font-black">Total a Pagar</span>
          <span className="text-[14px] font-black">
            ${granTotal.toFixed(2)}
          </span>
        </div>
      </div>

      <div className="ticket-divider"></div>

      {/* 6. PIE DE PÁGINA */}
      <div className="text-center space-y-1 mt-4 text-black">
        <div className="text-[9.5px] font-black uppercase tracking-widest">
          Club Campestre Lourdes
        </div>
        <div className="text-[8.5px] font-bold">
          Control de Consumos
        </div>
      </div>
    </div>
  );
};
